package Loop;

// Print all odd numbers divisible by 3 from 1 to 100
public class DivisibleBy3 {

	public static void main(String[] args) {
		// TODO Auto-generated method stub
		for(int i =1; i<=33; i++) {
			if(i%2 !=0) {
				System.out.println(3*i);
			}
		}
		System.out.println("khjgh");
		

	}

}
